import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v10 (Christianity - remaining) ===');

w('profiles_v10','united-methodist-church',{"brand_name":"United Methodist Church","brand_slug":"united-methodist-church","parent_company":"United Methodist Church","ultimate_parent":"Council of Bishops","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE UNITED METHODIST CHURCH SPLIT IN HALF OVER LGBTQ INCLUSION — OVER $600 MILLION IN PROPERTY WAS AT STAKE — AND THE DENOMINATION THAT STAYED INCLUSIVE NOW HAS TO REBUILD FROM A SMALLER BASE","executive_summary":"The United Methodist Church (UMC) is the second-largest Protestant denomination in the United States with approximately 5 million US members and 12 million globally. In 2022-2024, the UMC experienced the largest denominational split in American Protestantism in decades — with theologically conservative congregations departing to form the Global Methodist Church over the question of LGBTQ inclusion, particularly same-sex marriage and the ordination of openly LGBTQ clergy. Over 7,500 congregations (approximately 25% of US UMC churches) voted to disaffiliate, taking approximately $600 million in property. The remaining UMC voted in 2024 to remove its historic prohibition on same-sex marriage and LGBTQ ordination. The financial and membership consequences of the split will take years to fully assess.","verdict_tags":["7500_congregations_disaffiliated","600m_property_split","global_methodist_church_conservative_departure","lgbtq_inclusion_vote_2024","wespath_21b_pension_fund","clergy_sexual_misconduct_documented","connectional_structure_financial_complexity"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":true},"labor":{"summary":"The UMC employs approximately 30,000 clergy and significant lay staff across its connectional structure. The split has created documented employment uncertainty for clergy in departing congregations and for denominational staff. Clergy sexual misconduct has been a documented issue — the UMC has a formal complaint and response process, and the Council of Bishops has addressed multiple cases.","flags":["clergy_sexual_misconduct_formal_process","split_employment_uncertainty"],"sources":[]},"environmental":{"summary":"The UMC has official positions on environmental stewardship and climate change — generally supportive of action — through its Social Principles. Its Wespath investment fund manages approximately $21 billion in pension assets with documented ESG considerations.","flags":["wespath_21b_esg_investment","social_principles_climate_support"],"sources":[]},"political":{"summary":"The UMC's denominational split reflects the most consequential internal political division in American mainline Protestantism since the 19th century slavery-era splits. The conservative Global Methodist Church has aligned with African and Asian UMC conferences that voted against LGBTQ inclusion. The remaining UMC's 2024 vote to remove prohibitions on same-sex marriage and LGBTQ ordination represents the culmination of a 50-year internal debate.","flags":["50_year_lgbtq_debate_culmination","african_asian_conference_conservative_alignment","global_methodist_church_formed"],"sources":[]},"legal":{"summary":"The disaffiliation process required departing congregations to pay a financial exit cost — calculated as a share of denominational pension liabilities — generating significant litigation in multiple annual conference jurisdictions where congregations contested the exit terms. Courts have issued varying rulings on whether departing congregations could take their property. The $600 million in property involved in disaffiliations represents the largest property dispute in American Protestant history.","flags":["disaffiliation_exit_cost_litigation","600m_property_dispute_largest_protestant","annual_conference_court_rulings_varying"],"sources":[]},"tax":{"summary":"The UMC and its affiliated entities are exempt from federal income tax. Wespath — the denominational pension fund — manages approximately $21 billion in assets for clergy and lay employees. The disaffiliation financial settlements — including exit payments from departing congregations — represent a novel financial transaction in the nonprofit religious sector with tax implications that are still being assessed.","flags":["wespath_21b_pension_fund","disaffiliation_tax_implications_assessed"],"sources":[]},"executives":{"summary":"The Council of Bishops — currently 46 active bishops — governs the UMC. Bishop Thomas Bickerton chairs the Council. The denomination's handling of the split — including the negotiated disaffiliation process — has been managed through a complex interplay of the Council of Bishops, the Judicial Council (the denomination's supreme court), and General Conference (the global legislative body that meets every four years). The 2024 General Conference was the decisive legislative moment removing LGBTQ prohibitions.","flags":["council_bishops_46_active","2024_general_conference_decisive_vote","judicial_council_supreme_court"],"sources":[]},"connections":{"summary":"The UMC's connectional structure — where congregations, annual conferences, and the general church are financially linked — means the disaffiliation split has financial ripple effects across pension obligations, apportionments, and denominational budgets that will take years to resolve. The departing Global Methodist Church has aligned with more conservative theological networks internationally.","flags":["connectional_financial_ripple_effects","global_methodist_international_conservative_alignment"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Progressive UMC advocates have alleged that the disaffiliation process — which allowed conservative congregations to leave with their property in exchange for exit payments — represented a financial settlement that disproportionately benefited departing congregations at the expense of the remaining denomination and its pension obligations. Conservative departing congregations have alleged the exit costs were punitive and designed to deter departure. Both characterizations reflect genuine theological and financial disputes rather than established facts.","flags":["exit_cost_disputed_both_sides"],"sources":[]},"health_record":{"summary":"No major public health enforcement actions against the UMC have been identified. The LGBTQ inclusion debate — particularly the denomination's historic position that homosexuality is 'incompatible with Christian teaching' (now removed) — has been documented by researchers as contributing to spiritual harm for LGBTQ United Methodists over the decades the prohibition was in effect.","flags":["incompatible_with_christian_teaching_historic_position_harm_documented","position_removed_2024"],"sources":[]},"alternatives":{"cheaper":["Evangelical Methodist Church — smaller, conservative Methodist alternative","African Methodist Episcopal Church — historic Black Methodist denomination with different structure"],"healthier":["The remaining UMC — now fully inclusive — for LGBTQ United Methodists","Reconciling Ministries Network tracks affirming UMC congregations"],"diy":["UMC's official Wespath pension disclosures are available at wespath.org","The 2024 General Conference proceedings are publicly available through UMC.org"]},"timeline":[{"year":1972,"event":"UMC General Conference adds 'incompatible with Christian teaching' language about homosexuality to Social Principles","severity":"high","source_url":""},{"year":2019,"event":"Special General Conference adopts Traditional Plan strengthening LGBTQ prohibitions; progressive churches signal departure intentions","severity":"critical","source_url":""},{"year":2022,"event":"Disaffiliation process begins; thousands of conservative congregations begin voting to leave","severity":"critical","source_url":""},{"year":2022,"event":"Global Methodist Church formally launches as destination denomination for departing UMC congregations","severity":"high","source_url":""},{"year":2024,"event":"General Conference removes 'incompatible with Christian teaching' language; approves same-sex marriage and LGBTQ ordination; disaffiliation closes","severity":"critical","source_url":""}],"community_impact":{"displacement":"LGBTQ United Methodists who remained in the denomination through decades of 'incompatible with Christian teaching' language — and who experienced the split from the conservative wing — have experienced documented spiritual harm from an institution that debated their full humanity for 50 years before voting for inclusion. Departing conservative congregations have experienced the disruption of leaving a 150-year institutional home.","price_illusion":"The UMC's connectional structure presents as financial solidarity — apportionments from local congregations fund global ministry. The disaffiliation process revealed the complexity of unwinding these financial connections when theological disagreement breaks the connection.","tax_math":"The $600 million in property involved in disaffiliations — exempt from property and income tax as religious property — represents one of the largest tax-exempt asset transfers in American religious history.","wealth_velocity":"Wespath's $21 billion in pension assets represents the accumulated retirement savings of clergy and lay employees across both the remaining UMC and the departing Global Methodist Church — whose pension obligations remain with Wespath."},"cost_absorption":{"who_benefited":[{"group":"Departing congregations (Global Methodist Church)","how":"Retained local property in exchange for exit payments; departed with physical assets built over generations of connectional giving"}],"who_paid":[{"group":"LGBTQ United Methodists","how":"50 years of 'incompatible with Christian teaching' in official denominational doctrine; split and financial disruption to the inclusive denomination they remained in"},{"group":"Remaining UMC pension fund","how":"Pension obligations for departing clergy remain; smaller contribution base to fund them"}],"the_gap":"The United Methodist Church said homosexuality was incompatible with Christian teaching for 52 years. 7,500 congregations left when that changed. They took $600 million in property. The remaining denomination voted to remove the prohibition in 2024. The pension fund has $21 billion and a smaller base to fund it. The split is the largest in American Protestantism in a century. Both sides claim the other caused it."}});

w('profiles_v10','flds-church',{"brand_name":"FLDS Church","brand_slug":"flds-church","parent_company":"Fundamentalist Church of Jesus Christ of Latter-Day Saints","ultimate_parent":"Warren Jeffs (imprisoned)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"WARREN JEFFS RAN A THEOCRATIC COMPOUND WHERE HE ARRANGED MARRIAGES BETWEEN ADULT MEN AND GIRLS AS YOUNG AS 12 — HE IS SERVING LIFE PLUS 20 YEARS AND IS STILL ISSUING COMMANDS FROM PRISON","executive_summary":"The Fundamentalist Church of Jesus Christ of Latter-Day Saints (FLDS) is a polygamous fundamentalist Mormon splinter group that broke from the mainstream LDS Church when it abandoned plural marriage in 1890. Under Warren Jeffs — who led the FLDS from 2002 until his imprisonment — the organization operated as a theocratic system centered on the Yearning for Zion Ranch in Eldorado, Texas and the twin border towns of Hildale, Utah and Colorado City, Arizona. Jeffs arranged marriages between adult men and girls as young as 12, had dozens of wives himself including underage girls, expelled thousands of boys ('Lost Boys') from the community to reduce male competition for wives, and controlled members through complete economic and social dependence on the organization. Jeffs was convicted in 2011 on two counts of sexual assault of a child and aggravated sexual assault of a child — sentenced to life plus 20 years. He has continued issuing religious directives from prison that his followers obey.","verdict_tags":["jeffs_life_plus_20_years_child_sexual_assault","girls_as_young_as_12_arranged_marriages","lost_boys_thousands_expelled","yft_ranch_2008_texas_raid_439_children","jeffs_still_issuing_directives_from_prison","economic_social_total_control","hildale_colorado_city_theocratic_control","polygamy_underage_girls_documented"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"FLDS members worked in FLDS-controlled businesses — construction, manufacturing, agriculture — with wages often paid to the organization rather than to individual members. The United Effort Plan (UEP) — the community property trust that held most FLDS members' housing and property — was placed under state receivership by Utah courts in 2005 after Jeffs fled from state authorities. Members who left the FLDS typically did so with no personal assets, no credit history, and no marketable credentials outside the community.","flags":["wages_paid_to_organization_not_members","uep_trust_state_receivership_2005","members_exit_no_assets_no_credit_history","flds_controlled_businesses_labor_capture"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against FLDS have been identified.","flags":[],"sources":[]},"political":{"summary":"The FLDS exercised near-total political control over Hildale, Utah and Colorado City, Arizona — the twin border towns where the majority of members lived. Local law enforcement (the Colorado City Marshal's Office) was staffed by FLDS members who enforced community rules rather than state law — documented by the Arizona Attorney General's investigation. The community blocked outside businesses, controlled housing through the UEP trust, and expelled members who challenged Jeffs's authority. The political control was so complete that state governments of Utah, Arizona, and Texas all took legal action against various FLDS entities.","flags":["hildale_colorado_city_police_flds_members","arizona_ag_investigation_police_documented","uep_state_receivership_utah","total_political_community_control","three_state_legal_actions"],"sources":[]},"legal":{"summary":"2006: Warren Jeffs placed on FBI Ten Most Wanted list; arrested in Nevada. 2007: Jeffs convicted in Utah of rape as an accomplice (arranging marriage of 14-year-old to adult cousin); conviction later overturned on jury instruction error. 2008: Texas Rangers raid Yearning for Zion Ranch; 439 children taken into state custody — the largest child protective action in Texas history; children ultimately returned after courts found insufficient evidence of individual abuse for most children. 2011: Jeffs convicted in Texas on two counts of sexual assault of a child (a 12-year-old) and aggravated sexual assault of a child (a 15-year-old); sentenced to life plus 20 years plus $10,000 fine. 2012: UEP trust distributed to members and former members by Utah court. Jeffs continues to issue religious directives from prison.","flags":["jeffs_life_plus_20_2011_texas","fbi_ten_most_wanted","yfz_raid_439_children_largest_texas_cps","uep_distributed_utah_court_2012","jeffs_prison_directives_ongoing"],"sources":["https://www.justice.gov/usao-wdtx/pr/warren-jeffs-sentenced-life-plus-20-years"]},"tax":{"summary":"The United Effort Plan (UEP) trust — which held most FLDS members' housing and property — was placed under state receivership by Utah courts and ultimately distributed to members and former members. FLDS organizations have claimed religious tax exemption. The economic control structure — where members' labor and wages flowed to FLDS-controlled entities — represents a documented system of economic extraction under religious cover.","flags":["uep_state_receivership_distributed","economic_extraction_under_religious_tax_exemption"],"sources":[]},"executives":{"summary":"Warren Jeffs — 'prophet, seer, and revelator' of the FLDS — is serving life plus 20 years in Texas for child sexual assault. He has issued religious directives from prison that a portion of his followers continue to obey, including dietary restrictions, dress codes, and relationship rules. Jeffs succeeded his father Rulon Jeffs as FLDS prophet in 2002. Lyle Jeffs — Warren's brother — was convicted in 2017 of food stamp fraud for diverting food assistance money from members' EBT cards to FLDS-controlled accounts; he fled before sentencing and was later caught.","flags":["jeffs_life_plus_20","jeffs_directives_from_prison_obeyed","lyle_jeffs_food_stamp_fraud_convicted_fled"],"sources":["https://www.justice.gov/usao-wdtx/pr/warren-jeffs-sentenced-life-plus-20-years"]},"connections":{"summary":"The FLDS is the largest of several fundamentalist Mormon polygamous groups that broke from the mainstream LDS Church. The Kingston Group, the Apostolic United Brethren, and other groups share similar origins but are organizationally distinct. The mainstream LDS Church has explicitly and repeatedly disavowed the FLDS and all polygamous fundamentalist groups.","flags":["largest_of_multiple_fundamentalist_polygamous_groups","mainstream_lds_explicit_disavowal"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former FLDS members — including Jeffs's own nephew Brent Jeffs, who wrote a memoir — have alleged that sexual abuse of children within the community was systematic and multigenerational, and that the organizational structure was specifically designed to prevent reporting to outside authorities through complete social, economic, and informational control. These allegations are consistent with the documented criminal findings but extend to claimed patterns beyond the specific acts for which Jeffs was convicted.",
"flags":["systematic_multigenerational_abuse_alleged","structure_designed_prevent_reporting_alleged"],"sources":[]},"health_record":{"summary":"Warren Jeffs was convicted of sexually assaulting girls aged 12 and 15. He arranged marriages between adult men and girls as young as 12 — documented in evidence presented at trial. 'Lost Boys' — young men expelled from the community to reduce male competition for wives — were documented by researchers to face severe adjustment difficulties including substance abuse, homelessness, and inability to function outside the community's total control structure. Members who escaped documented psychological trauma from systematic isolation and control.","flags":["12_year_old_sexual_assault_convicted","lost_boys_expulsion_documented_harm","members_escape_psychological_trauma_documented"],"sources":["https://www.justice.gov/usao-wdtx/pr/warren-jeffs-sentenced-life-plus-20-years"]},"alternatives":{"cheaper":["There is no alternative to the FLDS for members whose entire social, economic, and family structure is controlled by the organization — exit requires rebuilding everything simultaneously"],"healthier":["Holding Out HELP (holdingouthelp.org) — support organization for individuals leaving polygamous fundamentalist groups","Flora Jessop's organization — former FLDS member who assists those leaving"],"diy":["The Texas court records from the YFZ Ranch case and Warren Jeffs's trial are public","'Stolen Innocence' by Elissa Wall and 'Church of Lies' by Flora Jessop are documented first-person accounts"]},"timeline":[{"year":1890,"event":"Mainstream LDS Church discontinues polygamy; fundamentalist members who continue are eventually excommunicated, forming FLDS predecessors","severity":"neutral","source_url":""},{"year":2002,"event":"Warren Jeffs succeeds father Rulon Jeffs as FLDS prophet; begins systematic consolidation of control","severity":"high","source_url":""},{"year":2005,"event":"Utah court places UEP trust under state receivership","severity":"critical","source_url":""},{"year":2006,"event":"Jeffs placed on FBI Ten Most Wanted; arrested in Nevada with underage 'spiritual wife'","severity":"critical","source_url":""},{"year":2008,"event":"Texas Rangers raid YFZ Ranch; 439 children removed — largest CPS action in Texas history; children returned after court rulings","severity":"critical","source_url":""},{"year":2011,"event":"Jeffs convicted in Texas: life plus 20 years for sexual assault of 12-year-old and 15-year-old","severity":"critical","source_url":"https://www.justice.gov/usao-wdtx/pr/warren-jeffs-sentenced-life-plus-20-years"},{"year":2017,"event":"Lyle Jeffs convicted of food stamp fraud; had diverted EBT funds from members to FLDS accounts; fled before sentencing; recaptured","severity":"critical","source_url":""}],"community_impact":{"displacement":"Thousands of 'Lost Boys' — young men expelled from the FLDS to reduce male competition for wives — were released into outside communities with no money, no education credentials, no credit, no identification documents in many cases, and no experience navigating non-FLDS society. Women who escaped faced similar challenges plus the additional complexity of leaving with children in jurisdictions where their marriages (to men who took multiple wives) had uncertain legal status.","price_illusion":"The FLDS presents as a restored form of original Mormon Christianity — a return to the plural marriage practices discontinued under government pressure. Members are told their eternal salvation depends on obedience to the prophet. The 'price' of this salvation is total surrender of property, income, marriage choice, and reproductive autonomy to Warren Jeffs — who is serving life in prison for child rape.","tax_math":"The UEP trust — which held members' housing, businesses, and land — operated as a tax-exempt religious trust while functioning as a mechanism of economic control that prevented members from accumulating personal assets. When the trust was placed under state receivership and distributed, members received assets they had effectively already paid for through their labor.","wealth_velocity":"The FLDS's economic model — where member labor and wages flowed to organization-controlled entities — concentrated assets in the UEP trust controlled by Warren Jeffs and FLDS leadership while members held no personal assets. Jeffs himself accumulated dozens of 'spiritual wives' whose reproductive labor created children for his household."},"cost_absorption":{"who_benefited":[{"group":"Warren Jeffs and FLDS leadership","how":"Complete economic, social, reproductive, and spiritual control over thousands of members; labor and wages of members captured by organization"},{"group":"Adult male FLDS members with allocated wives","how":"Access to multiple wives arranged by Jeffs; economic labor of wives and children"}],"who_paid":[{"group":"Girls assigned as wives to adult men","how":"Jeffs arranged marriages between adult men and girls as young as 12; Jeffs himself convicted of sexually assaulting girls aged 12 and 15"},{"group":"'Lost Boys' expelled from community","how":"Expelled with nothing to reduce male competition for wives; documented homelessness, substance abuse, inability to function outside the only society they knew"}],"the_gap":"Warren Jeffs arranged marriages between adult men and girls as young as 12. He sexually assaulted a 12-year-old and a 15-year-old. He is serving life plus 20 years. He is still issuing religious commands from prison. His followers still obey them. He expelled thousands of teenage boys from the community so older men could have more wives. Those boys were dropped on the street with nothing. The Texas Rangers took 439 children from his compound. Most were returned. Jeffs is still the prophet."}});

w('profiles_v10','westboro-baptist-church',{"brand_name":"Westboro Baptist Church","brand_slug":"westboro-baptist-church","parent_company":"Westboro Baptist Church","ultimate_parent":"Phelps family","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"WESTBORO BAPTIST CHURCH PICKETS MILITARY FUNERALS WITH 'GOD HATES FAGS' SIGNS — THE SUPREME COURT RULED 8-1 THAT THIS IS PROTECTED SPEECH — THE ENTIRE ORGANIZATION IS ONE EXTENDED FAMILY","executive_summary":"Westboro Baptist Church (WBC) is a small Topeka, Kansas-based congregation of approximately 70-100 members, almost all of whom are members of the extended Phelps family — descendants of founder Fred Phelps. Despite its tiny size, WBC has had extraordinary cultural impact through its strategy of picketing military funerals, LGBT events, Jewish institutions, and other locations with signs bearing slogans including 'God Hates Fags,' 'Thank God for Dead Soldiers,' and 'God Hates Jews.' The church's picketing of the funeral of Marine Lance Corporal Matthew Snyder led to the Supreme Court case Snyder v. Phelps (2011) — in which the Court ruled 8-1 that WBC's speech, however offensive, was protected by the First Amendment. The organization is designated a hate group by the SPLC and other organizations. Its founder Fred Phelps died in 2014 — reportedly having been excommunicated from his own church shortly before his death.","verdict_tags":["god_hates_fags_military_funerals","snyder_v_phelps_8_1_first_amendment_protected","splc_hate_group_designation","70_100_members_entire_phelps_family","fred_phelps_excommunicated_own_church","picketing_jewish_institutions_schools","legal_training_enables_harassment_within_law"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"WBC members are almost all members of the extended Phelps family. Many adult members are lawyers — a deliberate strategic choice that allows the organization to conduct its protest activities within the precise boundaries of First Amendment protection while maximizing legal counter-leverage against municipalities that attempt to restrict their activities.","flags":["majority_members_lawyers_strategic_choice","first_amendment_precision_documented"],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified.","flags":[],"sources":[]},"political":{"summary":"WBC's political philosophy is that the United States — and the world — is under divine judgment for tolerating homosexuality, Judaism, and other practices WBC condemns. This theology drives picketing of military funerals (soldiers die because America tolerates gays), Jewish institutions (for rejecting Jesus), and Catholic churches (for harboring child abusers, in WBC's framing). WBC has also picketed other Protestant churches, mosques, and schools. WBC members have traveled internationally to protest in countries including the UK (where Fred Phelps's daughter Shirley Phelps-Roper was banned from entry). WBC does not register lobbyists or engage in conventional political activity.","flags":["divine_judgment_theology_drives_all_activity","military_funeral_picketing_protected_speech","international_protests_uk_banned","catholic_jewish_mosque_protestant_all_targeted"],"sources":[]},"legal":{"summary":"Snyder v. Phelps (2011): Supreme Court rules 8-1 that WBC's picketing at Matthew Snyder's military funeral was protected First Amendment speech on matters of public concern. Chief Justice Roberts wrote the majority; only Justice Alito dissented. WBC has used its legal knowledge to remain within First Amendment protection while maximizing psychological impact. It has collected significant damages from municipalities and law enforcement that attempted to improperly restrict its activities — creating a documented revenue stream from civil rights violations against WBC that funds its protest travel.","flags":["snyder_v_phelps_8_1_2011","municipalities_damages_revenue_stream","legal_knowledge_maximizes_impact_within_law"],"sources":["https://www.supremecourt.gov/opinions/10pdf/09-751.pdf"]},"tax":{"summary":"WBC is registered as a Baptist church and claims tax exemption. Its finances are not publicly disclosed. The organization collects damages from municipalities that improperly restrict its activities — a revenue stream documented by journalists covering the organization. Its pickets are self-funded through member labor.","flags":["tax_exempt_church","municipal_damages_revenue","finances_not_disclosed"],"sources":[]},"executives":{"summary":"Fred Phelps founded WBC in 1955. He was reportedly excommunicated from his own church in 2013 — shortly before his death in March 2014 — by members of his own family, after he allegedly suggested the church should adopt a kinder approach. Shirley Phelps-Roper — Fred's daughter — is the most publicly visible current spokesperson. The church is governed entirely by the Phelps family. Fred Phelps was a civil rights attorney in the 1960s who successfully litigated desegregation cases in Kansas — a biographical fact that complicates the simple hate group narrative but does not change the documented conduct.","flags":["fred_phelps_civil_rights_attorney_1960s","fred_phelps_excommunicated_own_church_2013","shirley_phelps_roper_spokesperson","entirely_family_governed"],"sources":[]},"connections":{"summary":"WBC's primary connection is the legal precedent it has established — Snyder v. Phelps is a significant First Amendment case that protects speech on public matters regardless of how offensive it is. WBC has paradoxically contributed to First Amendment jurisprudence that protects all speech. Its influence on hate group discourse is primarily symbolic — its extreme visibility has made it a reference point for debates about speech, hate, and legal limits.","flags":["snyder_v_phelps_first_amendment_precedent","symbolic_reference_point_hate_group_debate"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former WBC members — including Fred Phelps's granddaughter Megan Phelps-Roper, who left and wrote a memoir — have alleged that children raised in WBC were subjected to psychological abuse through the organization's extremist theology, were isolated from the outside world, and were used as props in protests from a young age without capacity to consent. Megan Phelps-Roper's memoir 'Unfollow' documents her experience from the inside.","flags":["children_raised_psychological_isolation_alleged","protest_use_from_young_age_documented_megan"],"sources":[]},"health_record":{"summary":"WBC's picketing of military funerals — with signs including 'Thank God for Dead Soldiers' — has been documented to cause severe psychological harm to grieving military families. The Supreme Court acknowledged the harm but found the speech constitutionally protected. The organization's theology — that God kills soldiers as punishment for America's tolerance of homosexuality — represents documented psychological harm delivered to families at their most vulnerable moments.","flags":["military_family_grief_documented_harm","supreme_court_acknowledged_harm_protected_anyway"],"sources":["https://www.supremecourt.gov/opinions/10pdf/09-751.pdf"]},"alternatives":{"cheaper":["Any other Baptist congregation"],"healthier":["Megan Phelps-Roper's 'Unfollow' (2019) documents exit from WBC — resource for those in similar extremist religious environments"],"diy":["Snyder v. Phelps Supreme Court opinion is publicly available — documents both the harm and the First Amendment analysis","Counter-protest organizations including Planting Peace operate near WBC's Topeka location"]},"timeline":[{"year":1955,"event":"Fred Phelps founds Westboro Baptist Church in Topeka, Kansas","severity":"neutral","source_url":""},{"year":1991,"event":"WBC begins its first major protest campaign — against a Topeka park it claimed was a gay cruising site","severity":"high","source_url":""},{"year":2006,"event":"WBC pickets funeral of Marine Lance Corporal Matthew Snyder; Snyder's father sues","severity":"critical","source_url":""},{"year":2011,"event":"Supreme Court rules 8-1 in Snyder v. Phelps: WBC's speech at military funerals is constitutionally protected","severity":"critical","source_url":"https://www.supremecourt.gov/opinions/10pdf/09-751.pdf"},{"year":2013,"event":"Fred Phelps reportedly excommunicated from his own church by family members","severity":"high","source_url":""},{"year":2014,"event":"Fred Phelps dies; Shirley Phelps-Roper continues as primary spokesperson","severity":"neutral","source_url":""},{"year":2019,"event":"Megan Phelps-Roper publishes 'Unfollow' — memoir of growing up in and leaving WBC","severity":"moderate","source_url":""}],"community_impact":{"displacement":"Military families who experienced WBC picketing at their loved ones' funerals have documented severe and lasting psychological harm. The Supreme Court acknowledged this harm and ruled the speech protected. Matthew Snyder's father Albert Snyder — who initially won an $11 million judgment before it was overturned and he was ordered to pay WBC's legal costs — spent years in litigation with the organization that picketed his son's funeral.","price_illusion":"WBC presents as a remnant of authentic Calvinist theology that other churches have abandoned. Its 70-100 members are almost entirely one family. Its influence is wildly disproportionate to its size — a function of its deliberate media strategy of maximum offense at maximum visibility events.","tax_math":"WBC collects damages from municipalities that improperly restrict its protests — a revenue stream that funds its travel to protests nationwide. These damages come from public funds. The organization's tax exemption covers its operations.","wealth_velocity":"WBC's revenue model — tax exemption plus municipal damages for First Amendment violations — is unique. Fred Phelps's background as a civil rights attorney enabled the precision legal strategy that keeps WBC within constitutional protection while maximizing harm."},"cost_absorption":{"who_benefited":[{"group":"WBC/Phelps family","how":"First Amendment protection for maximally offensive speech; municipal damages fund protest travel; media coverage amplifies tiny group to global recognition"}],"who_paid":[{"group":"Military families at funerals","how":"WBC pickets with 'Thank God for Dead Soldiers' signs; Albert Snyder won $11M judgment then was ordered to pay WBC's costs"},{"group":"LGBTQ individuals and communities","how":"'God Hates Fags' signs at funerals, pride events, schools — documented psychological harm at maximum vulnerability moments"}],"the_gap":"Fred Phelps was a civil rights attorney who desegregated Topeka schools in the 1960s. Then he founded a church that pickets military funerals with 'Thank God for Dead Soldiers' signs. The Supreme Court said 8-1 that this is protected speech. His own family excommunicated him from his own church before he died. His granddaughter wrote a book about escaping. The organization has 70 members and they are almost all one family. Albert Snyder won $11 million for them picketing his son's funeral. The courts made him pay their legal costs instead."}});

w('profiles_v10','word-of-faith-fellowship',{"brand_name":"Word of Faith Fellowship","brand_slug":"word-of-faith-fellowship","parent_company":"Word of Faith Fellowship","ultimate_parent":"Jane Whaley (founder-leader)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"WORD OF FAITH FELLOWSHIP PRACTICES 'BLASTING' — MEMBERS SCREAM AT EACH OTHER FOR HOURS TO CAST OUT DEMONS — FORMER MEMBERS DOCUMENT PHYSICAL ABUSE, CHILD LABOR, AND MEMBERS SENT TO BRAZIL TO CONCEAL CRIMES","executive_summary":"Word of Faith Fellowship (WOFF) is a Spindale, North Carolina-based evangelical church founded by Jane Whaley in 1979 with approximately 750 members. It has been investigated by law enforcement and documented by the Associated Press in a Pulitzer Prize-winning investigative series as operating as a controlling high-demand religious group with documented physical abuse. WOFF's signature practice is 'blasting' — where members are subjected to hours of loud screaming by other members to cast out demons. Former members have documented systematic physical abuse of children in the name of discipline, members being sent to a Brazilian sister congregation to remove them from US law enforcement jurisdiction when legal trouble arose, labor exploitation of members, and total control over members' personal lives, communications, and relationships. Jane Whaley has never been criminally charged despite investigations by multiple agencies.","verdict_tags":["blasting_hours_screaming_cast_demons","ap_pulitzer_prize_investigation","physical_abuse_children_documented","brazil_sister_congregation_jurisdiction_escape","jane_whaley_never_charged_investigations","total_control_communications_relationships","labor_exploitation_documented","former_members_criminal_charges_obstruction"],"concern_flags":{"labor":true,"environmental":false,"political":false,"tax":true,"health":true,"legal":true},"labor":{"summary":"Former WOFF members have documented being directed to work in church-controlled businesses for below-market or no wages, with the labor controlled by Whaley's direction. The AP investigation documented that WOFF members worked in painting, landscaping, and other businesses where their labor was directed by church leadership with minimal individual compensation.","flags":["church_controlled_business_labor_documented","below_market_no_wage_documented","ap_investigation_labor_exploitation"],"sources":["https://apnews.com/special-reports/word-of-faith-fellowship"]},"environmental":{"summary":"No environmental enforcement actions against WOFF have been identified.","flags":[],"sources":[]},"political":{"summary":"WOFF does not engage in conventional political activity. Its political influence is limited to its effect on the Spindale, North Carolina community where it has significant local presence. Former members have alleged that local law enforcement's proximity to church members affected the responsiveness to abuse complaints in the community.","flags":["local_law_enforcement_proximity_alleged_effect"],"sources":[]},"legal":{"summary":"Multiple law enforcement investigations — by state agencies and the FBI — have been conducted into WOFF without resulting in charges against Jane Whaley. Former WOFF members — including children who were physically abused — filed criminal complaints that were not prosecuted. The AP documented that some members were sent to WOFF's Brazilian affiliate church when US legal scrutiny increased. Several former members and church leaders have faced charges related to obstruction of investigations and child abuse — but not Whaley herself. A 2017 Rutherford County, North Carolina grand jury investigated WOFF; no indictments were returned against Whaley.","flags":["multiple_investigations_no_whaley_charges","brazil_members_sent_jurisdiction_documented","former_members_charged_not_whaley","2017_grand_jury_no_indictment_whaley"],"sources":["https://apnews.com/special-reports/word-of-faith-fellowship"]},"tax":{"summary":"WOFF is registered as a tax-exempt religious organization. Its finances are not publicly disclosed. The church's control over member employment and labor — documented by the AP — represents an economic control structure that operates under religious exemption.","flags":["tax_exempt_no_public_disclosure","economic_control_religious_exemption"],"sources":[]},"executives":{"summary":"Jane Whaley founded WOFF in 1979 and remains its leader as of 2024. She has been described by former members as exercising complete authority over members' lives — including approving marriages, directing careers, controlling communication with family outside the church, and directing the blasting sessions. Her husband Sam Whaley is also in leadership. Despite multiple investigations, no criminal charges have been filed against Whaley. The AP's multi-year investigation won a Pulitzer Prize for Investigative Reporting in 2017.","flags":["whaley_no_criminal_charges_multiple_investigations","complete_authority_documented_ap","ap_pulitzer_2017"],"sources":["https://apnews.com/special-reports/word-of-faith-fellowship"]},"connections":{"summary":"WOFF operates a Brazilian affiliate church — the Comunidade Cristã Palavra da Fé in Curitiba — that has been documented as a destination for WOFF members sent outside US jurisdiction when legal scrutiny increased. The Brazilian church operates with similar practices to WOFF. WOFF is not affiliated with any denomination.","flags":["brazil_affiliate_curitiba_jurisdiction_escape","no_denominational_affiliation_accountability"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former WOFF members — including individuals who were raised in the church from childhood — have alleged systematic physical abuse during 'discipline' sessions, food deprivation as punishment, isolation from non-WOFF family members, prohibition on medical care without Whaley's approval, sleep deprivation through extended prayer and blasting sessions, and the use of the Brazil congregation to move members beyond US legal jurisdiction. These allegations are documented in the AP investigation but Whaley has not been criminally convicted.","flags":["systematic_physical_abuse_discipline_alleged","food_deprivation_punishment_alleged","medical_care_whaley_approval_required","sleep_deprivation_extended_blasting","brazil_legal_jurisdiction_escape_documented_ap"],"sources":["https://apnews.com/special-reports/word-of-faith-fellowship"]},"health_record":{"summary":"'Blasting' — the practice of having multiple members scream at a target member for hours to cast out demons — is documented by the AP and by former members as both physically and psychologically harmful. Former members have documented receiving or witnessing physical beatings during discipline sessions administered by adults including parents directed by church leadership. The prohibition on medical care without Whaley's approval has been documented to result in delayed or denied treatment for medical conditions. Children raised in WOFF have documented lasting psychological trauma from their upbringing.","flags":["blasting_physical_psychological_harm_documented","physical_beatings_discipline_documented","medical_care_approval_delayed_denied","children_lasting_trauma_documented"],"sources":["https://apnews.com/special-reports/word-of-faith-fellowship"]},"alternatives":{"cheaper":["Any other evangelical Christian congregation without a controlling high-demand structure"],"healthier":["BITE Model Awareness (bitemodel.org) — Steven Hassan's framework for evaluating controlling religious groups","Recovering from Religion Foundation — support for those leaving high-demand religious groups"],"diy":["The AP's Word of Faith Fellowship investigative series is publicly available at apnews.com","'Twisted Minds' documentary covers WOFF"]},"timeline":[{"year":1979,"event":"Jane Whaley founds Word of Faith Fellowship in Spindale, North Carolina","severity":"neutral","source_url":""},{"year":1995,"event":"First significant media and law enforcement attention to WOFF practices; ABC News 20/20 investigation","severity":"high","source_url":""},{"year":2012,"event":"Former members begin filing criminal complaints for abuse; law enforcement investigations begin","severity":"critical","source_url":""},{"year":2017,"event":"AP publishes Pulitzer Prize-winning investigation into WOFF; Brazil congregation documented as jurisdiction escape","severity":"critical","source_url":"https://apnews.com/special-reports/word-of-faith-fellowship"},{"year":2017,"event":"Rutherford County grand jury investigates WOFF; no indictments returned against Whaley","severity":"high","source_url":""}],"community_impact":{"displacement":"Children raised in WOFF who leave as adults face rebuilding their lives with limited outside relationships, limited education beyond what Whaley permitted, and the psychological effects of the practices they experienced. Former members who maintained contact with non-WOFF family members were subject to church discipline — making those connections difficult to maintain.","price_illusion":"WOFF presents as a Pentecostal Christian church focused on spiritual warfare and deliverance from demonic influence. The 'price' of membership — documented by the AP and by former members — includes submission to Whaley's authority over every major life decision, participation in blasting sessions, and the effective severing of relationships with non-members including biological family.","tax_math":"WOFF's tax-exempt religious status covers an organization that the AP documented as exercising economic control over members' labor, directing members to work in church-controlled businesses, and — per former members — controlling members' access to their own earnings.","wealth_velocity":"WOFF's economic control over member labor — through church-directed employment in church-controlled businesses — represents wealth accumulation through the directed labor of controlled members operating under religious exemption."},"cost_absorption":{"who_benefited":[{"group":"Jane Whaley and WOFF leadership","how":"Complete control over members' lives, labor, and relationships; labor directed to church-controlled businesses; no criminal charges despite multiple investigations"}],"who_paid":[{"group":"WOFF members — especially those raised from childhood","how":"Hours of blasting; physical abuse during 'discipline'; medical care requiring Whaley approval; isolation from family; labor directed by church; lasting psychological harm"}],"the_gap":"Word of Faith Fellowship has a practice called blasting where members scream at each other for hours to cast out demons. The AP won a Pulitzer Prize documenting it. Former members describe systematic physical abuse of children. Some members were sent to a church in Brazil when US law enforcement started looking. Multiple investigations have been conducted. Jane Whaley has never been charged with anything. The grand jury returned no indictments. The church is tax-exempt. It has 750 members."}});

w('profiles_v10','society-of-saint-pius-x',{"brand_name":"Society of Saint Pius X","brand_slug":"society-of-saint-pius-x","parent_company":"Society of Saint Pius X (SSPX)","ultimate_parent":"Superior General of the SSPX","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE SSPX BREAKAWAY CATHOLIC GROUP'S FOUNDER WAS EXCOMMUNICATED — ONE OF ITS BISHOPS SAID THE HOLOCAUST KILLED FAR FEWER THAN 6 MILLION — AND POPE BENEDICT LIFTED THE EXCOMMUNICATIONS ANYWAY","executive_summary":"The Society of Saint Pius X (SSPX) is a traditionalist Catholic organization founded in 1970 by French Archbishop Marcel Lefebvre in reaction to the Second Vatican Council's liturgical and theological reforms. The SSPX operates in a canonically irregular state — it has been in partial schism with Rome, then partially regularized, then in ongoing dialogue — conducting traditional Latin Mass sacraments that the Vatican has disputed as validly administered for decades. In 2009, Pope Benedict XVI lifted the excommunications of four SSPX bishops — including Bishop Richard Williamson, who had given a television interview days earlier stating that historical evidence was 'hugely against six million having been murdered' in the Holocaust and that 'not more than 200,000 to 300,000 Jews perished in Nazi concentration camps' in gas chambers. The timing of the excommunication lifting generated global outrage. Williamson was subsequently expelled from the SSPX for his continued Holocaust denial but had already been rehabilitated by Benedict's action.","verdict_tags":["williamson_holocaust_denial_200_300k_gas_chambers","benedict_lifted_excommunications_timing_williamson","lefebvre_excommunicated_1988_illicit_consecrations","sspx_canonical_irregular_status_ongoing","antisemitism_documented_multiple_leaders","traditional_latin_mass_sacramental_validity_disputed","williamson_expelled_sspx_continued_denial"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"SSPX operates seminaries, schools, and priories globally through a traditional religious community structure. No major documented labor violations have been identified beyond the canonical controversy of the organization's status.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the SSPX.","flags":[],"sources":[]},"political":{"summary":"The SSPX's political influence operates through its theological positions — rejection of Vatican II's declaration on religious liberty, its affirmation of prior Catholic statements about Judaism, and its traditional positions on social questions. Several SSPX bishops and priests have made documented antisemitic statements beyond Williamson's Holocaust denial. The SSPX has attracted members who combine traditionalist Catholicism with far-right political views — including in France, where it has connections to the political right. The SSPX does not engage in conventional political lobbying.","flags":["religious_liberty_rejection_vatican_ii","prior_antisemitic_statements_multiple_leaders","france_far_right_connections_documented"],"sources":[]},"legal":{"summary":"The SSPX's canonical status — following Marcel Lefebvre's 1988 illicit episcopal consecrations that resulted in automatic excommunication — has been the subject of ongoing Vatican negotiations. Pope Benedict XVI lifted the excommunications of the four SSPX bishops in January 2009. Bishop Richard Williamson had given a Swedish television interview in November 2008 (broadcast January 2009) denying the Holocaust scale — the interview's broadcast and the excommunication lifting occurred within days of each other. Williamson was subsequently expelled from the SSPX in 2012 for refusing to stop expressing Holocaust denial views. He founded his own group. Germany convicted Williamson in absentia for Holocaust denial (a crime in Germany) and fined him.","flags":["benedict_lifted_excommunications_williamson_timing","williamson_holocaust_denial_german_conviction","williamson_expelled_sspx_2012_founded_own_group","lefebvre_illicit_consecrations_1988"],"sources":[]},"tax":{"summary":"The SSPX and its affiliated entities claim religious tax exemption in the jurisdictions where they operate. Its financial operations are not publicly disclosed. The SSPX operates approximately 600 priories, 100 schools, and 2 universities globally — a significant institutional footprint.","flags":["600_priories_100_schools_2_universities","no_public_financial_disclosure"],"sources":[]},"executives":{"summary":"Don Davide Pagliarani is the current SSPX Superior General, elected in 2018. Marcel Lefebvre founded the SSPX in 1970, was excommunicated in 1988 for illicitly consecrating four bishops without papal mandate, and died in 1991. Bishop Richard Williamson — one of the four illicitly consecrated bishops whose excommunication was lifted in 2009 — was subsequently expelled from the SSPX in 2012 and founded his own traditionalist group, the Resistance. Williamson has continued making Holocaust denial statements.","flags":["pagliarani_current_superior_general","lefebvre_excommunicated_1988_died_1991","williamson_expelled_2012_resistance_founded"],"sources":[]},"connections":{"summary":"The SSPX occupies a complex position in Catholic ecclesiology — it maintains all traditional Catholic sacramental forms while being in irregular canonical status with Rome. Its chapels attract Catholics dissatisfied with post-Vatican II liturgical changes — ranging from mainstream traditionalists to those with far-right political sympathies. Pope Francis has extended broader recognition of SSPX marriages and confessions, further regularizing its de facto status while formal canonical regularization remains incomplete.","flags":["francis_extended_marriage_confession_recognition","mainstream_traditionalist_to_far_right_range","canonical_regularization_ongoing"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Jewish organizations and critics of the SSPX have alleged that the antisemitic statements made by Williamson and other SSPX clergy reflect theological positions embedded in pre-Vatican II Catholicism that the SSPX has preserved — including supersessionist theology that the mainstream Catholic Church revised at Vatican II. The SSPX disputes that its positions constitute antisemitism. Williamson's Holocaust denial is documented fact, not allegation; his positions on Jewish theological status reflect traditional pre-Vatican II Catholic theology that the mainstream Church has officially moved away from.","flags":["williamson_denial_documented_not_allegation","pre_vatican_ii_supersessionism_preserved_alleged"],"sources":[]},"health_record":{"summary":"No major public health enforcement actions against the SSPX have been identified. Its documented concern is primarily theological and historical — the rehabilitation of a bishop who denied the Holocaust, and the persistence of pre-Vatican II theological positions about Judaism that the mainstream Catholic Church revised specifically because of their relationship to antisemitism.","flags":["williamson_rehabilitation_theological_historical_concern"],"sources":[]},"alternatives":{"cheaper":["Institute of Christ the King Sovereign Priest — fully regularized traditionalist Catholic organization with canonical approval","Personal parishes celebrating the Traditional Latin Mass within diocesan structures — now more widely available under motu proprios"],"healthier":["Fully canonically regularized traditionalist Catholic communities without Holocaust denial leadership history"],"diy":["The Vatican's documentation of the Williamson excommunication lifting is publicly available","Richard Williamson's blog (since his SSPX expulsion) documents his ongoing Holocaust denial — primary source for understanding what was rehabilitated"]},"timeline":[{"year":1970,"event":"Marcel Lefebvre founds SSPX in Écône, Switzerland in reaction to Second Vatican Council reforms","severity":"neutral","source_url":""},{"year":1988,"event":"Lefebvre illicitly consecrates four bishops without papal mandate; automatic excommunications applied to Lefebvre and all four bishops including Williamson","severity":"critical","source_url":""},{"year":1991,"event":"Lefebvre dies while excommunicated","severity":"neutral","source_url":""},{"year":2008,"event":"November: Bishop Williamson gives Swedish television interview denying Holocaust scale — 200,000-300,000 in gas chambers, not 6 million","severity":"critical","source_url":""},{"year":2009,"event":"January: Interview broadcast. Days later, Pope Benedict XVI lifts excommunications of all four SSPX bishops including Williamson. Global outrage. Benedict expresses regret about timing.","severity":"critical","source_url":""},{"year":2012,"event":"SSPX expels Williamson for refusing to stop expressing Holocaust denial. Germany convicts Williamson in absentia for Holocaust denial.","severity":"critical","source_url":""},{"year":2018,"event":"Don Davide Pagliarani elected Superior General; ongoing Vatican regularization negotiations continue","severity":"neutral","source_url":""}],"community_impact":{"displacement":"Jewish communities globally responded with documented outrage to Pope Benedict XVI's lifting of Williamson's excommunication — with the interview denying the Holocaust's scale having broadcast days earlier. The timing was described by the Simon Wiesenthal Center and other organizations as a rehabilitation of a Holocaust denier at the highest level of Catholic institutional action.","price_illusion":"The SSPX presents as preserving authentic Catholic tradition against post-Vatican II distortions. It simultaneously preserved pre-Vatican II theological positions about Judaism that the mainstream Catholic Church revised specifically because of their relationship to the conditions that enabled the Holocaust — and one of its four bishops denied the Holocaust's scale.","tax_math":"The SSPX operates 600 priories, 100 schools, and 2 universities globally as tax-exempt religious entities without public financial disclosure.","wealth_velocity":"The SSPX's global institutional footprint — maintained through traditional Catholic tithing practices and estate gifts — is significant. Its financial operations are not publicly disclosed."},"cost_absorption":{"who_benefited":[{"group":"SSPX and its members","how":"Four bishops rehabilitated by papal action; canonical regularization gradually advancing; traditional liturgy increasingly legitimized by Francis-era motu proprios"}],"who_paid":[{"group":"Holocaust survivors and Jewish communities","how":"Pope Benedict lifted the excommunication of a bishop who said gas chambers killed 200,000-300,000 Jews, not 6 million — days after the interview aired"}],"the_gap":"Bishop Williamson said the Holocaust killed 200,000 to 300,000 Jews. He said gas chambers did not kill millions. This was broadcast in January 2009. Days later Pope Benedict lifted his excommunication. Benedict expressed regret about the timing. Germany convicted Williamson for Holocaust denial. The SSPX expelled him in 2012. He founded his own group. The other three bishops kept their rehabilitated status. The SSPX is still negotiating full regularization with Rome."}});

w('profiles_v10','greek-orthodox-ecumenical-patriarchate',{"brand_name":"Greek Orthodox / Ecumenical Patriarchate","brand_slug":"greek-orthodox-ecumenical-patriarchate","parent_company":"Ecumenical Patriarchate of Constantinople","ultimate_parent":"Ecumenical Patriarchate of Constantinople","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE ECUMENICAL PATRIARCH IS THE SPIRITUAL LEADER OF 300 MILLION ORTHODOX CHRISTIANS — HE OPERATES FROM ISTANBUL WHERE TURKEY HAS RESTRICTED HIS INSTITUTION FOR A CENTURY — AND THE GREEK ARCHDIOCESE OF AMERICA HAS A $40 MILLION FINANCIAL SCANDAL","executive_summary":"The Ecumenical Patriarchate of Constantinople is the historically senior institution of Eastern Orthodox Christianity, with the Ecumenical Patriarch holding a primacy of honor among Orthodox bishops globally. Patriarch Bartholomew I has led the Ecumenical Patriarchate since 1991 and has earned global recognition for his environmental advocacy — earning the title 'Green Patriarch.' The Ecumenical Patriarchate operates from the Phanar neighborhood of Istanbul, Turkey, in conditions of documented legal restriction — Turkey has not allowed the Patriarchate to reopen the Halki Theological Seminary (closed since 1971) and the Patriarch must be a Turkish citizen, limiting succession options. The Greek Orthodox Archdiocese of America — canonically under the Ecumenical Patriarchate — experienced a major financial scandal in 2018-2019 involving the St. Nicholas National Shrine rebuilding project at Ground Zero, where approximately $40 million in donations were mismanaged, construction halted, and the Archbishop was forced to resign.","verdict_tags":["halki_seminary_closed_turkey_1971","patriarch_must_be_turkish_citizen_succession_limit","st_nicholas_shrine_40m_financial_scandal","archbishop_demetrios_forced_resign","green_patriarch_environment_recognition","300_million_orthodox_spiritual_primacy","phanar_istanbul_documented_restriction"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":true},"labor":{"summary":"The Ecumenical Patriarchate and Greek Orthodox Archdiocese of America employ clergy and administrative staff under standard religious organization arrangements. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"Patriarch Bartholomew I has earned international recognition for environmental advocacy — meeting with world leaders including multiple US presidents and Pope Francis on climate issues, convening international environmental symposia, and issuing strong statements on climate change since the 1990s. He has been called the 'Green Patriarch.' The Ecumenical Patriarchate's environmental positions are among the most documented and consistent of any major religious institution.","flags":["green_patriarch_documented_environmental_leadership","climate_symposia_since_1990s","meetings_presidents_pope_francis"],"sources":[]},"political":{"summary":"The Ecumenical Patriarchate's most significant political challenge is its relationship with Turkey. The Turkish government closed the Halki Theological Seminary in 1971 under a law nationalizing private higher education — the only such institution that trained Orthodox clergy in Turkey. Despite decades of advocacy by US presidents, European leaders, and the Patriarch himself, Turkey has not reopened Halki. Turkey's requirement that the Patriarch be a Turkish citizen — with the Phanar's historically small Greek Orthodox community in Istanbul — creates a documented succession crisis as qualified candidates dwindle. The Patriarchate's role in the 2019 grant of autocephaly to the Ukrainian Orthodox Church (OCU) — over Moscow Patriarchate objections — has made it central to the ecclesiological dimensions of the Russia-Ukraine conflict.","flags":["halki_closed_1971_us_presidents_advocacy_failed","turkish_citizen_requirement_succession_crisis","ukraine_autocephaly_2019_moscow_schism"],"sources":[]},"legal":{"summary":"St. Nicholas National Shrine scandal: Following September 11, the Greek Orthodox Archdiocese of America undertook the rebuilding of St. Nicholas Greek Orthodox Church — the only house of worship destroyed on September 11 — as a national shrine at Ground Zero. The project raised approximately $40 million from donors. By 2019, construction had stalled, financial controls were found to be severely inadequate, the Port Authority suspended the Archdiocese from the site, and Archbishop Demetrios was forced to resign after 20 years. An independent audit found serious financial mismanagement. No criminal charges were filed but the scandal damaged the Archdiocese significantly.","flags":["st_nicholas_40m_mismanaged","port_authority_suspended_archdiocese","archbishop_demetrios_forced_resign","no_criminal_charges_significant_damage"],"sources":["https://www.nytimes.com/2019/09/05/nyregion/greek-orthodox-church-ground-zero.html"]},"tax":{"summary":"The Ecumenical Patriarchate and Greek Orthodox Archdiocese of America are exempt from US taxation on their religious activities. The Archdiocese files Form 990 — its finances are publicly available. The $40 million in St. Nicholas donations was received as tax-deductible charitable contributions that were subsequently mismanaged.","flags":["archdiocese_form_990_public","40m_tax_deductible_donations_mismanaged"],"sources":[]},"executives":{"summary":"Patriarch Bartholomew I (Dimitrios Arhondonis) has led the Ecumenical Patriarchate since 1991. Archbishop Elpidophoros Lambriniadis became Greek Orthodox Archbishop of America in 2019 — succeeding the resigned Archbishop Demetrios — and has undertaken significant financial reform of the Archdiocese while also becoming a more publicly active ecclesiastical presence. The St. Nicholas scandal that forced Demetrios's resignation occurred during a 20-year tenure otherwise characterized by pastoral stability.","flags":["elpidophoros_financial_reform_2019","demetrios_20_year_tenure_ended_scandal"],"sources":[]},"connections":{"summary":"The Ecumenical Patriarchate's grant of autocephaly to the Ukrainian Orthodox Church in 2019 — creating an independent Ukrainian church over Moscow Patriarchate objections — has made it a central institution in the ecclesiological dimensions of the Russia-Ukraine war. Patriarch Kirill of Moscow broke communion with the Ecumenical Patriarchate following the autocephaly grant. The Ecumenical Patriarchate's position as the historically senior Orthodox institution gives it moral authority that Russia has been attempting to delegitimize since 2019.","flags":["ukraine_autocephaly_russia_kyrill_schism","moscow_broke_communion_2019","moral_authority_russia_delegitimization_campaign"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The independent audit of the Greek Orthodox Archdiocese of America's finances — commissioned following the St. Nicholas scandal — found inadequate financial controls, lack of standard accounting practices, and commingling of funds across archdiocesan accounts. While no criminal conduct was identified, the audit found that the financial management was insufficiently rigorous for an organization managing $40 million in designated donor funds.","flags":["inadequate_financial_controls_audit_finding","commingling_funds_documented"],"sources":[]},"health_record":{"summary":"No major public health enforcement actions against the Greek Orthodox Archdiocese or Ecumenical Patriarchate have been identified. The St. Nicholas scandal's primary harm was financial — to donors who contributed $40 million for a specific purpose that was not achieved.","flags":["st_nicholas_40m_donor_harm_financial"],"sources":[]},"alternatives":{"cheaper":["Antiochian Orthodox Church — North American alternative Orthodox jurisdiction","Orthodox Church in America (OCA) — autocephalous US Orthodox jurisdiction"],"healthier":["Orthodox jurisdictions with documented financial transparency and independent audit practices"],"diy":["Greek Orthodox Archdiocese Form 990 is available at ProPublica Nonprofit Explorer","The St. Nicholas National Shrine website provides current project status"]},"timeline":[{"year":1923,"event":"Treaty of Lausanne: population exchange between Greece and Turkey; Greek Orthodox community in Istanbul dramatically reduced","severity":"high","source_url":""},{"year":1971,"event":"Turkey closes Halki Theological Seminary under private higher education nationalization law; not reopened as of 2024","severity":"critical","source_url":""},{"year":1991,"event":"Patriarch Bartholomew I elected; begins environmental advocacy that earns 'Green Patriarch' designation","severity":"neutral","source_url":""},{"year":2001,"event":"St. Nicholas Greek Orthodox Church destroyed September 11; Archdiocese begins planning national shrine","severity":"high","source_url":""},{"year":2019,"event":"Port Authority suspends Archdiocese from St. Nicholas site over mismanaged $40M; Archbishop Demetrios forced to resign after 20 years","severity":"critical","source_url":"https://www.nytimes.com/2019/09/05/nyregion/greek-orthodox-church-ground-zero.html"},{"year":2019,"event":"Ecumenical Patriarchate grants autocephaly to Ukrainian Orthodox Church; Moscow Patriarchate breaks communion","severity":"critical","source_url":""},{"year":2022,"event":"Russia invades Ukraine; Ecumenical Patriarchate's support for Ukrainian church independence becomes geopolitically significant","severity":"high","source_url":""}],"community_impact":{"displacement":"Greek Orthodox donors who contributed to the St. Nicholas National Shrine — the only house of worship destroyed on September 11 — contributed approximately $40 million that was mismanaged to the point where construction stalled and the Port Authority suspended the Archdiocese from the site. As of 2024, the shrine has resumed construction under new leadership.","price_illusion":"The St. Nicholas National Shrine was presented as a national memorial with profound symbolic significance — the rebuilding of the only church destroyed on September 11, at Ground Zero. $40 million was raised on this basis. The financial mismanagement that halted construction represents a significant breach of donor trust.","tax_math":"$40 million in tax-deductible charitable contributions were designated for the St. Nicholas shrine and were found to have been inadequately controlled — with commingling of funds and insufficient accounting practices documented in the independent audit.","wealth_velocity":"The Ecumenical Patriarchate operates with extremely limited resources relative to its spiritual significance — Turkey's restrictions have constrained its institutional development for a century."},"cost_absorption":{"who_benefited":[{"group":"Contractors and parties involved in halted construction","how":"Contracts paid from $40M in donor funds during the mismanagement period"}],"who_paid":[{"group":"St. Nicholas shrine donors","how":"$40M designated for rebuilding the only church destroyed on September 11; mismanaged to the point where construction stalled"}],"the_gap":"St. Nicholas was the only church destroyed on September 11. The Greek Orthodox Archdiocese raised $40 million to rebuild it as a national shrine. Construction stalled. The Port Authority threw them off the site. An audit found the financial management was inadequate. The Archbishop resigned after 20 years. No criminal charges were filed. Turkey still has not reopened the theological seminary it closed in 1971. The Patriarch must be a Turkish citizen. There are very few Greek Orthodox Turkish citizens. The succession is a documented institutional crisis."}});

w('profiles_v10','international-churches-of-christ',{"brand_name":"International Churches of Christ","brand_slug":"international-churches-of-christ","parent_company":"Multiple autonomous congregations (former Boston Movement)","ultimate_parent":"No central authority (post-2002 restructuring)","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE BOSTON MOVEMENT / ICOC WAS DOCUMENTED AS ONE OF THE MOST CONTROLLING RELIGIOUS ORGANIZATIONS IN AMERICA — IT COLLAPSED WHEN ITS FOUNDER WAS FORCED OUT — AND ITS CONTROLLING TACTICS REMAIN IN DOCUMENTED USE BY SOME AFFILIATED CHURCHES","executive_summary":"The International Churches of Christ (ICOC) — formerly called the Boston Movement — is a network of autonomous congregations that grew rapidly in the 1980s and 1990s under the leadership of Kip McKean, who built the movement from a single Boston congregation into a global network of over 100,000 members before its collapse in 2002. The ICOC was documented by cult researchers, journalists, and former members as one of the most psychologically controlling religious organizations in America — requiring members to have 'discipling partners' who monitored their spiritual and personal lives, imposing strict dating and sexual standards enforced through peer accountability, requiring disclosure of personal information to leaders, and using intense social pressure to prevent members from leaving. After McKean was forced out in 2002 amid scandals about his leadership conduct, the ICOC restructured as autonomous congregations. McKean subsequently founded a new organization — the International Christian Church (ICC) — which former members document as using the same controlling practices.","verdict_tags":["boston_movement_cult_documentation_extensive","discipling_partner_monitoring_control","kip_mckean_forced_out_2002_founded_icc","icc_same_practices_documented","campus_ministry_recruitment_documented","shunning_disfellowshipping_family_impact","cult_education_network_documented","rapid_growth_collapse_pattern"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":true,"legal":false},"labor":{"summary":"ICOC members in full-time ministry ('interns' and full-time staff) worked within a system where their compensation, housing, and social life were controlled by the organization. No formal legal labor violations have been documented, but former members have described conditions where leaving ministry employment meant simultaneously losing housing, income, and social community.","flags":["ministry_employment_housing_social_tied","exit_simultaneous_loss_multiple_dependencies"],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for the ICOC.","flags":[],"sources":[]},"political":{"summary":"The ICOC does not engage in conventional political advocacy. Its influence operates through its campus ministry recruitment — historically targeting college students — and through its control over members' personal lives rather than through political lobbying.","flags":["campus_ministry_recruitment_college_students","personal_life_control_not_political_lobbying"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against the ICOC or its successor organizations have been documented. The organization's practices — discipling partnerships, confession of personal information to leaders, intensive accountability structures — have been extensively documented by cult researchers and former members but have not resulted in criminal prosecution. Campus ministries at universities have been banned from operating on some campuses based on their documented practices. Harvard University banned the Boston Church of Christ from campus in the 1980s.","flags":["harvard_campus_ban_1980s","no_criminal_prosecution","cult_researcher_documentation_extensive","some_universities_banned"],"sources":[]},"tax":{"summary":"ICOC congregations are tax-exempt religious organizations. Their finances are managed at the congregational level following the 2002 restructuring. Kip McKean's new ICC organization is separately tax-exempt. No major tax enforcement actions have been documented.","flags":["congregational_tax_exemption","post_restructuring_decentralized"],"sources":[]},"executives":{"summary":"Kip McKean built the Boston Movement from a single Gainesville, Florida congregation (1979) through Boston (1979) and then globally. He was forced to step down in 2002 amid widespread member criticism of his authoritarian leadership style and reports of abuse. He subsequently founded the International Christian Church (ICC) in 2006, which former members document as operating with the same controlling practices as the original ICOC. Current ICOC leadership is decentralized across autonomous congregations globally.","flags":["mckean_forced_out_2002","mckean_founded_icc_2006_same_practices","decentralized_post_restructuring"],"sources":[]},"connections":{"summary":"The ICOC's campus ministry recruitment model — targeting college freshmen through friendship and social integration before introducing religious expectations — has been documented by cult researchers as a sophisticated gradual commitment technique. The 'love bombing' recruitment strategy and subsequent discipling control structure have been analyzed in academic literature on high-demand groups. Former members have documented the practices' psychological impact in extensive testimony.","flags":["love_bombing_gradual_commitment_documented_academic","high_demand_group_academic_analysis","former_member_testimony_extensive"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former ICOC and ICC members have alleged that the discipling system — requiring disclosure of personal information, sexual history, and doubts to accountability partners who report to leaders — created conditions where leaving felt psychologically impossible, where personal information was used as leverage, and where members who left were shunned by the community they had been integrated into. These practices are documented in cult research literature but have not been prosecuted.","flags":["personal_information_leverage_alleged","leaving_psychologically_impossible_conditions_alleged","shunning_departure_documented"],"sources":[]},"health_record":{"summary":"Former ICOC and ICC members — particularly those who were recruited as college students — have documented depression, anxiety, and PTSD following exit from the organization. The combination of total social integration into the group, disclosure of personal information to accountability partners, and the social consequences of leaving (shunning) creates a documented pattern of psychological harm that cult researchers characterize as consistent with high-demand group dynamics.","flags":["depression_anxiety_ptsd_former_members_documented","high_demand_group_psychological_harm_pattern","college_student_recruitment_vulnerability"],"sources":[]},"alternatives":{"cheaper":["Mainstream Churches of Christ — the denominational tradition from which the ICOC broke — without the discipling control structure","Non-denominational evangelical churches without mandatory accountability partnerships"],"healthier":["Christian communities without mandatory disclosure structures and social pressure to remain","Recovery resources: Recovering from Religion, BITE Model Awareness"],"diy":["The Cult Education Network (culteducation.com) has extensive documentation of ICOC practices","Former members maintain documentation at REVEAL (reveal.org)"]},"timeline":[{"year":1979,"event":"Kip McKean revitalizes a small Church of Christ congregation in Gainesville, Florida; begins developing 'discipling' theology","severity":"neutral","source_url":""},{"year":1979,"event":"McKean moves to Boston; builds the Boston Church of Christ; begins rapid international expansion","severity":"neutral","source_url":""},{"year":1988,"event":"Movement adopts 'International Churches of Christ' name; global membership approaches 100,000","severity":"neutral","source_url":""},{"year":1992,"event":"Harvard University bans ICOC-affiliated campus ministry; documented pattern of campus restrictions begins","severity":"high","source_url":""},{"year":2002,"event":"Kip McKean forced to step down amid widespread leadership criticism; ICOC restructures as autonomous congregations","severity":"critical","source_url":""},{"year":2006,"event":"McKean founds International Christian Church (ICC) with same discipling practices; former ICOC members document continuation","severity":"critical","source_url":""}],"community_impact":{"displacement":"College students recruited into the ICOC — particularly those who became deeply integrated into the community's social structure — have documented losing their entire social network, sometimes their academic progress, and their psychological equilibrium when they left or were pushed out. The recruitment strategy targeting college freshmen — at a period of high social vulnerability — is documented as specifically effective at integration.","price_illusion":"The ICOC presents as a high-commitment Christian community — authentic discipleship modeled on early Christianity. Former members document that the commitment required extends to disclosure of personal information, monitoring of dating and sexual life, and social consequences for leaving that were not disclosed during recruitment.","tax_math":"ICOC congregations are tax-exempt. Their financial practices — including requirements that members contribute significant portions of income — are not subject to public disclosure at the congregational level.","wealth_velocity":"The ICOC's rapid growth model — where new congregations in new cities were 'planted' by trained members from existing churches — created a rapidly scaling organization funded by member contributions. The decentralization following McKean's departure makes current financial tracking impossible."},"cost_absorption":{"who_benefited":[{"group":"ICOC/ICC leadership including Kip McKean","how":"Built a global organization of 100,000+ members through a recruitment and control model documented by cult researchers; founded new ICC after forced departure from ICOC"}],"who_paid":[{"group":"College students recruited into ICOC/ICC","how":"Social integration followed by disclosure requirements and control structures; departure costs including loss of entire social network; documented psychological harm"}],"the_gap":"The Boston Movement recruited college freshmen. They called it friendship. Then they called it discipleship. You disclosed your sexual history to your discipling partner. Your discipling partner reported to a leader. When members left they lost their entire social network simultaneously. Harvard banned them from campus in 1992. Kip McKean was forced out in 2002. He started a new organization in 2006 with the same practices. Former members document the same patterns. It is tax-exempt."}});

